import {render, remove, RenderPosition} from '../render.js';
import SortView from '../view/sort.js';
import EventListView from '../view/event-list.js';
import EmptyView from '../view/empty.js';
import LoadingView from '../view/loading.js';
import PointPresenter from './point.js';
import TripInfoView from '../view/trip-info.js';
import {UpdateType, UserAction, FilterType, DEFAULT_POINT, SortType} from '../const.js';
import {filter} from '../utils/filter.js';
import UiBlocker from '../framework/ui-blocker/ui-blocker.js';

const FAILED_LOAD_MESSAGE = 'Failed to load latest route information';
const TimeLimit = {
  LOWER_LIMIT: 350,
  UPPER_LIMIT: 1000,
};


export default class TripPresenter {
  #container;
  #pointsModel;
  #filterModel;
  #pointPresenters = new Map();
  #currentSort = SortType.DAY;
  #sortView = null;
  #eventListView = null;
  #emptyView = null;
  #loadingView = null;
  #newEventView = null;
  #newPointDestroyCallback = null;
  #isLoading = true;
  #isError = false;
  #tripInfoView = null;
  #tripMainElement = null;

  constructor(container, pointsModel, filterModel) {
    this.#container = container;
    this.#pointsModel = pointsModel;
    this.#filterModel = filterModel;
    this.#tripMainElement = document.querySelector('.trip-main');
    this.#pointsModel.addObserver(this.#handleModelEvent);
    this.#filterModel.addObserver(this.#handleModelEvent);
  }

  init() {
    this.#loadingView = new LoadingView();
    render(this.#loadingView, this.#container);
  }

  createPoint(onDestroy) {
    this.#currentSort = SortType.DAY;
    this.#filterModel.setFilter(UpdateType.MAJOR, FilterType.EVERYTHING);
    this.#handleModeChange();

    if (!this.#eventListView) {
      this.#eventListView = new EventListView();
      render(this.#eventListView, this.#container);
    }

    if (this.#emptyView) {
      remove(this.#emptyView);
      this.#emptyView = null;
    }

    this.#newPointDestroyCallback = onDestroy;

    const destinations = this.#pointsModel.getDestinations();
    const offersByType = this.#pointsModel.getOffersByType();
    const defaultPoint = {...DEFAULT_POINT};

    import('../view/event-edit.js').then(({default: EventEditView}) => {
      this.#newEventView = new EventEditView(
        defaultPoint,
        destinations[0] ?? {id: null, name: '', description: '', pictures: []},
        offersByType,
        destinations,
        async (point) => {
          this.#newEventView.setSaving();
          try {
            await this.#handleUserAction(UserAction.ADD_POINT, UpdateType.MINOR, point);
          } catch {
            this.#newEventView.setAborting();
          }
        },
        this.#closeNewEvent,
        () => {},
        true
      );

      document.addEventListener('keydown', this.#onNewEventEscKeydown);
      render(this.#newEventView, this.#eventListView.element, 'afterbegin');
    });
  }

  #getFilteredPoints() {
    return filter[this.#filterModel.getFilter()](this.#pointsModel.getPoints());
  }

  #getSortedPoints() {
    const points = this.#getFilteredPoints();
    switch (this.#currentSort) {
      case SortType.TIME:
        return points.slice().sort((a, b) => (b.dateTo - b.dateFrom) - (a.dateTo - a.dateFrom));
      case SortType.PRICE:
        return points.slice().sort((a, b) => b.basePrice - a.basePrice);
      default:
        return points.slice().sort((a, b) => a.dateFrom - b.dateFrom);
    }
  }

  #destroyNewEvent() {
    if (!this.#newEventView) {
      return;
    }
    remove(this.#newEventView);
    this.#newEventView = null;
    document.removeEventListener('keydown', this.#onNewEventEscKeydown);
    this.#newPointDestroyCallback?.();
    this.#newPointDestroyCallback = null;
  }

  #closeNewEvent = () => {
    this.#destroyNewEvent();
    if (this.#pointsModel.getPoints().length === 0) {
      this.#renderEmpty();
    }
  };

  #onNewEventEscKeydown = (evt) => {
    if (evt.key === 'Escape') {
      evt.preventDefault();
      this.#closeNewEvent();
    }
  };

  #renderBoard() {
    if (this.#isLoading) {
      return;
    }

    if (this.#isError) {
      this.#emptyView = new EmptyView();
      this.#emptyView.element.textContent = FAILED_LOAD_MESSAGE;
      render(this.#emptyView, this.#container);
      return;
    }

    const points = this.#getFilteredPoints();

    if (points.length === 0) {
      this.#renderEmpty();
      return;
    }

    this.#renderSort();
    this.#eventListView = new EventListView();
    render(this.#eventListView, this.#container);
    this.#renderPoints();
  }

  #renderTripInfo() {
    if (this.#tripInfoView) {
      remove(this.#tripInfoView);
      this.#tripInfoView = null;
    }

    const points = this.#pointsModel.getPoints();
    if (this.#isError || points.length === 0) {
      return;
    }

    this.#tripInfoView = new TripInfoView(points);
    render(this.#tripInfoView, this.#tripMainElement, RenderPosition.AFTERBEGIN);
  }

  #renderEmpty() {
    this.#emptyView = new EmptyView(this.#filterModel.getFilter());
    render(this.#emptyView, this.#container);
  }

  #renderSort() {
    this.#sortView = new SortView(this.#currentSort, this.#handleSortChange);
    render(this.#sortView, this.#container);
  }

  #renderPoints() {
    this.#getSortedPoints().forEach((point) => {
      const destination = this.#pointsModel.getDestinationById(point.destinationId);
      const pointPresenter = new PointPresenter(
        this.#eventListView.element,
        point,
        destination,
        this.#pointsModel.getOffersByType(),
        this.#pointsModel.getDestinations(),
        this.#handleUserAction,
        this.#handleModeChange
      );
      pointPresenter.init();
      this.#pointPresenters.set(point.id, pointPresenter);
    });
  }

  #clearBoard(resetSort = false) {
    this.#destroyNewEvent();
    this.#pointPresenters.forEach((presenter) => presenter.destroy());
    this.#pointPresenters.clear();

    if (this.#sortView) {
      remove(this.#sortView);
      this.#sortView = null;
    }
    if (this.#eventListView) {
      remove(this.#eventListView);
      this.#eventListView = null;
    }
    if (this.#emptyView) {
      remove(this.#emptyView);
      this.#emptyView = null;
    }

    if (resetSort) {
      this.#currentSort = SortType.DAY;
    }
  }

  #handleUserAction = async (userAction, updateType, point) => {
    this.#uiBlocker.block();
    try {
      switch (userAction) {
        case UserAction.UPDATE_POINT:
          await this.#pointsModel.updatePoint(updateType, point);
          break;
        case UserAction.ADD_POINT:
          await this.#pointsModel.addPoint(updateType, point);
          break;
        case UserAction.DELETE_POINT:
          await this.#pointsModel.deletePoint(updateType, point);
          break;
      }
    } finally {
      this.#uiBlocker.unblock();
    }
  };

  #handleModelEvent = (updateType, point) => {
    switch (updateType) {
      case UpdateType.PATCH:
        this.#pointPresenters.get(point.id)?.update(point, this.#pointsModel.getDestinationById(point.destinationId));
        this.#renderTripInfo();
        break;
      case UpdateType.MINOR:
        this.#clearBoard();
        this.#renderBoard();
        this.#renderTripInfo();
        break;
      case UpdateType.MAJOR:
        this.#clearBoard(true);
        this.#renderBoard();
        this.#renderTripInfo();
        break;
      case UpdateType.INIT:
        this.#isLoading = false;
        remove(this.#loadingView);
        this.#renderBoard();
        this.#renderTripInfo();
        break;
      case UpdateType.ERROR:
        this.#isLoading = false;
        this.#isError = true;
        remove(this.#loadingView);
        this.#renderBoard();
        this.#renderTripInfo();
        break;
    }
  };

  #handleModeChange = () => {
    this.#destroyNewEvent();
    this.#pointPresenters.forEach((presenter) => presenter.resetView());
  };

  #handleSortChange = (sortType) => {
    if (sortType === this.#currentSort) {
      return;
    }
    this.#currentSort = sortType;
    this.#clearBoard();
    this.#renderBoard();
  };

  #uiBlocker = new UiBlocker({
    lowerLimit: TimeLimit.LOWER_LIMIT,
    upperLimit: TimeLimit.UPPER_LIMIT,
  });
}
